{"code":"import json, re
path_all = var_call_lXffAlzOT6nABH4YHECXfTdo
with open(path_all, 'r', encoding='utf-8') as f:
    all_recs = json.load(f)
uc_pubs = var_call_GTe40MYYN2iFvAozGlmaJG46
# ensure uc_pubs is a list
if isinstance(uc_pubs, str):
    uc_pubs = json.loads(uc_pubs)
uc_set = set(uc_pubs)

assignee_to_codes = {}

for rec in all_recs:
    cit_text = rec.get('citation','')
    if not cit_text or cit_text.strip()=='[]':
        continue
    try:
        cit_list = json.loads(cit_text)
    except Exception:
        # try to fix single quotes
        try:
            cit_list = json.loads(cit_text.replace("'", '"'))
        except Exception:
            continue
    cites_uc = False
    for c in cit_list:
        pubnum = c.get('publication_number','')
        if pubnum in uc_set:
            cites_uc = True
            break
    if not cites_uc:
        continue
    # extract assignee from Patents_info
    pi = rec.get('Patents_info','').strip()
    assignee = None
    # common patterns
    patterns = [r'^(.*?)\s+(?:holds|hold|has|has been|is|is owned by|is assigned to|assigned to|belongs to)\b',
                r'^(.*?),\s+with',
                r'^(.*)\s+has\s+pub\.',
                r'^(.*?)\s+owns\b']
    for p in patterns:
        m = re.search(p, pi, re.IGNORECASE)
        if m:
            assignee = m.group(1).strip(' ,')
            break
    if not assignee:
        # fallback: take up to first 'holds' or 'owns' or 'assigned' occurrence
        m = re.split(r'\s+(?:holds|is assigned to|assigned to|is owned by|has|owns)\b', pi, flags=re.IGNORECASE)
        if len(m)>1:
            assignee = m[0].strip(' ,')
        else:
            assignee = pi
    # normalize
    assignee = re.sub(r'\s+', ' ', assignee).strip()
    if 'UNIV CALIFORNIA' in assignee.upper():
        continue
    # parse cpc
    cpc_text = rec.get('cpc','')
    try:
        cpc_list = json.loads(cpc_text) if cpc_text and cpc_text.strip()!='[]' else []
    except Exception:
        try:
            cpc_list = json.loads(cpc_text.replace("'", '"'))
        except Exception:
            cpc_list = []
    primary_codes = [entry.get('code') for entry in cpc_list if entry.get('first')==True and entry.get('code')]
    # if no primary found, maybe use first entry's code
    if not primary_codes and cpc_list:
        first_code = cpc_list[0].get('code')
        if first_code:
            primary_codes = [first_code]
    if not primary_codes:
        continue
    assignee_to_codes.setdefault(assignee, set()).update(primary_codes)

# convert sets to sorted lists
out = {a: sorted(list(codes)) for a,codes in assignee_to_codes.items()}
print("__RESULT__:")
print(json.dumps(out))"}

{"code":"import json, re
raw = var_call_rdomNQQuPMbOJdLOHCAMVciX
# raw is a JSON string or dict
if isinstance(raw, str):
    data = json.loads(raw)
else:
    data = raw
assignee_map = {}
codes_set = set()
for raw_key, codes in data.items():
    s = raw_key
    # Try to extract assignee name from the Patents_info-like string
    # common patterns: '... is assigned to X' or 'X holds the' or 'X holds the US ...' etc.
    # We'll look for leading segment before 'holds', 'is assigned to', 'is assigned', 'is owned by', 'assigned to', 'has publication', 'has publication number', 'has publication no.'
    m = re.split(r'\b(?:holds|hold|is assigned to|assigned to|is owned by|is owned|has publication number|has publication no\.|has publication no|has publication|has pub\.|has publication|has pub|has\s+publication|has publication number|is assigned)\b', s, flags=re.IGNORECASE)
    if m and m[0].strip():
        assignee = m[0].strip().strip(',.')
    else:
        # fallback: take text between start and 'the US' or 'the US patent'
        m2 = re.match(r'^(.*?)\s+the\s+US\b', s, flags=re.IGNORECASE)
        if m2:
            assignee = m2.group(1).strip().strip(',.')
        else:
            assignee = s
    assignee = re.sub(r'\s+', ' ', assignee)
    # remove leading 'The' if present
    assignee = re.sub(r'^The\s+', '', assignee, flags=re.IGNORECASE)
    assignee_map[assignee] = codes
    for c in codes:
        codes_set.add(c)

out = {'assignee_to_codes': assignee_map, 'codes': sorted(list(codes_set))}
print('__RESULT__:')
print(json.dumps(out))"}

